/**
 * Methods that triggers URL change event
 *
 * hash - hash change
 * history - history API change (popState, pushState, go, back, forward)
 * both (default) - both hash and history changes
 */
export enum TriggeringMethod {
  HASH = 'hash',
  BOTH = 'both',
  HISTORY = 'history',
}

export enum TRIGGER_TYPE {
  CLICK = 'click',
  PAGE_VIEW = 'page_view',
  VIEW = 'view',
  API_AFTER = 'api_after',
  STAY_DURATION = 'stay_duration',
};

export const PAGE_STATS_CACHE_KEY = 'VISUAL_STAY_DURATION_STATS';

export const ActivityEvent = {
  KEY_DOWN: 'keydown',
  MOUSE_DOWN: 'mousedown',
  MOUSE_OVER: 'mouseover',
  TOUCH_START: 'touchstart',
  TOUCH_END: 'touchend',
  SCROLL: 'scroll',
};

export const DEBOUNCE_TIMEOUT = 50;
export const INACTIVE_TIMEOUT = 30000;